__attribute__((used)) HandlerFunc GeneratedFindSuperOpcode(const DecodedOp* ops) {
    if (!ops) return nullptr;
    static std::atomic<GeneratedSuperOpcodeTable*> table_ptr{nullptr};
    auto* table = table_ptr.load(std::memory_order_acquire);
    if (!table) {
        auto* new_table = BuildGeneratedSuperOpcodeTable();
        auto* expected = static_cast<GeneratedSuperOpcodeTable*>(nullptr);
        if (!table_ptr.compare_exchange_strong(expected, new_table, std::memory_order_acq_rel,
                                               std::memory_order_acquire)) {
            delete new_table;
            table = expected;
        } else {
            table = new_table;
        }
    }

    auto it = table->find(GeneratedSuperOpcodeKey{ops[0].handler, ops[1].handler});
    return it != table->end() ? it->second : nullptr;
}

